var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"직할 도시 로터스, 제5 격납고","JPN":"直轄都市ロータス、第5格納庫","ENG":"Direct Control City, Lotus, Hangar 5","TWN":"直轄城市洛德斯，第5機庫"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 4","JPN":"CSE Lv.4","ENG":"CSE Lv. 4","TWN":"CSE Lv. 4"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"CSE 레벨이 4까지 상승했다!","JPN":"CSEレベルが4まで上昇した！","ENG":"CSE Level just hit 4!","TWN":"CSE等級上升到4了！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"자기 머리에 총알 박아 넣고 싶지 않은 녀석은 이터니움 쉴드를 확인해라!","JPN":"自分の頭に弾をぶち込みたくないやつは、エタニウムシールドを確認しろ！","ENG":"If you do not want a bullet in your own head, check your Eternium shield!","TWN":"不想讓自己的腦袋被貫穿的傢伙，都給我檢查永恆之金護盾！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHIELD_SL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_SL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이봐! 정신 차려! 뭐 하고 있는 거야!","JPN":"おい！　しっかりしろ！　何してるんだ！","ENG":"Hey! Snap out of it! What are you doing?!","TWN":"喂！振作點！你在做什麼！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SHIELD_SL_NULL_NULL","text":{"KOREA":"저거… 저거 안 보여?","JPN":"あれ……あれが見えないのか？","ENG":"Hey... don't you see that?","TWN":"那個……你沒看到那個嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_SL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHIELD_SL_NULL_NULL","text":{"KOREA":"저 똑같이 생긴 저 그림자들…….","JPN":"あの、どいつも同じ姿をしたシャドウ……","ENG":"Those identical Shadows...","TWN":"那些長得一模一樣的影子……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_SL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SHIELD_SL_NULL_NULL","text":{"KOREA":"예전에 토벌되었다던 그 그림자 아니야?","JPN":"前に討伐されたって言ってたあのシャドウじゃないか？","ENG":"Are they not the same Shadows we were told got wiped out before?","TWN":"是之前被討伐的那些影子吧？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_SL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"젠장! 식별명, 미니스트라와 유사한 개체 다수 조우!","JPN":"くそ！　識別名ミニストラに類似した個体複数に遭遇！","ENG":"Damn it! Multiple encounters with Ministra-like entities!","TWN":"可惡！遇到多數與識別名迷你斯特拉相似的個體！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"추가 지원을 요청한다!","JPN":"追加支援を要請する！","ENG":"Requesting additional support!","TWN":"請求追加支援！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"추가 지원을……!","JPN":"追加支援を……！","ENG":"Requesting additio–","TWN":"追加支援……！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흐, 흐아아아앗?!","JPN":"ふ、ふああああっ！？","ENG":"W-whoaaa?!","TWN":"呃、呃啊啊啊？！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"놈들이 벌써 여기까지 밀고 들어왔다고?!","JPN":"もうここまで迫ってるって！？","ENG":"They already pushed in this far?!","TWN":"它們已經攻到這裡了？！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"우리 쪽에도 방위선을 세워둔 것 아니었어??","JPN":"こっちにも防衛線を構築したんじゃなかったの？","ENG":"Didn't we establish a defense line on our side too??","TWN":"我們這邊不是也設好防線了嗎？？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저 그림자들은 평범한 침식체가 아닌 것 같습니다.","JPN":"あのシャドウは普通の侵食体ではないようです。","ENG":"Those Shadows don't seem like ordinary C.O.s.","TWN":"那些影子看起來不像普通的侵蝕體。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"식별명 미니스트라와 유사한 그림자들… 어쩌면 마왕과 관련이 있을지도 모르겠군요.","JPN":"識別名ミニストラに類似した複数のシャドウ……もしかすると、魔王と関係があるかもしれません。","ENG":"Shadows similar to Code Name: Ministra... They may be tied to the Demon Lord.","TWN":"與識別名迷你斯特拉相似的影子……說不定與魔王有關。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 너무 걱정하진 마십시오.","JPN":"でも、あまり心配しないでください。","ENG":"But not to worry.","TWN":"但請別太擔心。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"흡!","JPN":"ふっ！","ENG":"Hup!","TWN":"呼！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L43_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"제가 버티는 이상, 시니어님에게 털끝 하나 건드리지 못할 테니까요.","JPN":"私がいる以上、シニア様には指一本触れさせません。","ENG":"As long as I stand here, not a hair on you will be touched, Senior.","TWN":"只要我還在，就不會讓它們碰到您一根寒毛。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"파, 파티마…….","JPN":"ファ、ファティマ……","ENG":"F-Fatima...","TWN":"法、法蒂瑪……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"괜찮습니다, 시니어님.","JPN":"大丈夫です、シニア様。","ENG":"It is all right, Senior.","TWN":"沒事的，Senior。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"제게 무슨 일이 생기더라도 최우선 경호 대상인 당신을 버리는 일은 없을 겁니다.","JPN":"私に何かあっても、最優先警護対象であるあなたを見捨てることはありません。","ENG":"No matter what happens to me, I will not abandon the person I am sworn to protect.","TWN":"您是我最優先的保護對象，就算我出了什麼事也絕不會放棄您。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"동시다발적으로 재건 도시들을 습격한 건, 이걸 노린 거였을까?","JPN":"これを狙って、同時多発的に再建都市を攻めてきたのかな？","ENG":"Did they hit the reconstruction cities all at once just to set this up?","TWN":"同時襲擊重建城市，難道就是為了這個？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그럴 가능성이 높습니다만… 왜 구태여 이런 방법을 택했는지 의문이군요.","JPN":"その可能性は高いですが……なぜわざわざこのような手段を選んだのか疑問です。","ENG":"Likely so... Though why choose such a roundabout method is puzzling.","TWN":"可能性很高……但我也覺得很奇怪為什麼偏要用這種方式。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전투원들을 분산시켜 발을 묶은 뒤 직할 도시에 병력을 집중시키다니…….","JPN":"相手の戦力を分散させては足止めし、直轄都市に兵力を集中させるなんて……","ENG":"Split our fighters and tie them down, then mass on the Direct Control City...","TWN":"先分散戰鬥人員牽制我們，再集中兵力攻擊直轄城市……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그냥 처음부터 직할 도시를 침공하는 것이 훨씬 쉬운 일일 텐데 말입니다.","JPN":"最初から直轄都市を一点集中して攻めるほうが、遥かに簡単な方法のはずです。","ENG":"It would have been easier to attack the Direct Control City from the start.","TWN":"明明從一開始就進攻直轄城市更簡單啊。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 지금 그걸 고민할 때가 아닙니다.","JPN":"でも、今考えても仕方がありません。","ENG":"But this is not the time to debate it.","TWN":"但現在不是想這些的時候了。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"여기서 시니어님이 전사하신다면 지금까지 저희가 해왔던 모든 것이 무용지물.","JPN":"ここでシニア様が戦死したら、今まで私たちのやってきたことがすべて水の泡になりますから。","ENG":"If you fall here, everything we have done becomes pointless.","TWN":"如果Senior在這裡戰死，那我們到現在做的一切都將化為泡影。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"격납고 내부에 벙커가 있으니 그곳으로 피신하시는 게…….","JPN":"格納庫の内部にシェルターがあります。そこに……","ENG":"There is a bunker inside the hangar. You should take shelt–","TWN":"機庫內有掩體，您應該先撤退……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"나는 퓨처 앳 워 인공지능 연구소의 엠버 소장이라고 해.","JPN":"私はフューチャーアットウォー人工知能研究所の所長、アンバーよ。","ENG":"I am Director Ember of Future-at-War's AI Research Lab.","TWN":"我是天啟兵器人工智能研究所的所長琥珀。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"오늘까지는 말이지. 아니, 어쩌면 내일일지도……?","JPN":"今日まではね。いや、もしかしたら明日までかも……？","ENG":"At least until today. Or maybe tomorrow...?","TWN":"至少到今天為止。不對，說不定能撐到明天……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"하지만 누군가는 책임질 각오가 필요했으니까…….","JPN":"でも、責任を取る覚悟ができる、誰かが必要だった……","ENG":"Someone had to be ready to take responsibility...","TWN":"但總得有人要有負起責任的覺悟……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NPC_GIRL","text":{"KOREA":"네? 무슨 말인지 잘 모르겠어요…….","JPN":"え？　なんのこと？","ENG":"Huh? What do you mean...?","TWN":"咦？我聽不太懂……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"후후, 아무것도 아냐, 너한테는 좀 어려운 얘기였으려나?","JPN":"ふふ、何でもない。あなたには少し難しすぎたかな。","ENG":"Haha, nothing. Maybe it's a bit much for you to understand right now.","TWN":"呵呵，沒什麼。對妳來說太難懂了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"어른이란 족속들은 아무리 힘들고 외로워도 포기해선 안 되는 상황이 오기 마련이거든.","JPN":"大人というのはね、どんなに辛くても寂しくても、諦めちゃいけない時があるの。","ENG":"There come times when adults can't give up, no matter how hard or lonely it gets.","TWN":"大人啊，無論再怎麼辛苦、再怎麼孤單，總會遇到不能放棄的時候。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이제서야 당신이 했던 그 말, 이해할 수 있게 되었어……","JPN":"今ならわかる気がする……あの時、あなたが言った言葉……","ENG":"I finally understand what you meant by that...","TWN":"現在我終於能明白你說過的話了……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"난 여기 끝까지 남아서 선로전환기 준비 작업을 계속하고 있을게.","JPN":"私は最後までここに残って、線路転換器の準備作業を続けるよ。","ENG":"I'm staying here to keep prepping the Track Switcher to the very end.","TWN":"我會留在這裡，繼續準備線路轉換器的工作。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"너무 위험한 일입니다!","JPN":"危険すぎます！","ENG":"That is far too dangerous!","TWN":"這太危險了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님이 고집불통이란 건 잘 알고 있습니다.","JPN":"シニア様が頑固なのはよくわかっています。","ENG":"I know you can be stubborn.","TWN":"我知道Senior很固執。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 이건 여러 사람의 목숨이 달린 문제입니다.","JPN":"しかし今は、何人もの命がかかっているのですよ！","ENG":"But this is about many lives.","TWN":"但這牽涉到很多人的性命。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님 한 분의 목숨에 얼마나 많은 사람이…….","JPN":"シニア様1人の命に、どれだけ多くの人が……","ENG":"How many people for the sake of a single life–","TWN":"有多少人的性命會因為您……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내가 어렸을 때, 시민들을 지키기 위해 얼마나 많은 사람들이 죽었는지 알아?","JPN":"まだ私が子どもだった頃、とても多くの人たちが、市民を守るために死んでいった。","ENG":"Do you know how many died to protect civilians when I was a kid?","TWN":"你知道我小時候有多少人為了保護市民而死嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"모두가 죽음을 각오하고 침식체에게 맞설 때 나타난 게 바로 타이탄이었어.","JPN":"みんなが決死の覚悟で侵食体に立ち向かった時に現れたのが、タイタンだった。","ENG":"Titan arrived when everyone braced for death and stood against the C.O.s.","TWN":"大家抱著必死無疑的覺悟反抗侵蝕體時，那時後挺身而出的就是泰坦。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"모든 사람이 장난감이라고 욕하던 그게 사람을 구했다고.","JPN":"みんなたかがおもちゃと笑ってたあれが、人を助けたの。","ENG":"The thing people mocked as a toy is what saved lives.","TWN":"那個被大家罵說是玩具的東西拯救人類的性命。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"자신이 쫓겨날 것을 각오하고 타이탄을 반출한 엠버 소장에 의해서 말이야.","JPN":"追い出されることを覚悟してタイタンを搬出した、アンバー所長によってね。","ENG":"Because Director Ember risked being banished to deploy Titan.","TWN":"琥珀所長冒著自己被逐出的風險把泰坦運出來。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내, 내가 겁을 먹고 벙커에 숨어버리는 순간, 선로전환기가 파괴될지도 몰라.","JPN":"わ、私がビビっちゃって、もしシェルターに隠れたりでもしたら？　そのせいで線路転換器が破壊されてしまったら？","ENG":"If I panic and hide in a bunker now, the Track Switcher could be destroyed.","TWN":"如、如果我因為害怕躲進掩體，線路轉換器可能就在那瞬間被破壞。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래. 지금 당장은 괜찮을지도 모르지.","JPN":"今回は……それでも大丈夫かもしれない。","ENG":"Sure, it might now be right away.","TWN":"沒錯，現在或許還沒問題。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"알파트릭스 회장의 콜로서스 베이스가 선로전환기를 만들고 있으니까.","JPN":"アルファトリックス会長のコロッサスベースが線路転換器を作っているから。","ENG":"Because Alphatrix President's Colossus Base is fabricating the Track Switcher.","TWN":"阿爾法崔克斯會長的巨像基地正在製作線路轉換器。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하지만 선로전환기를 가동하기 위한 시스템은 내가 더 잘 알아.","JPN":"でも、線路転換器を稼働させるためのシステムについては私のほうがよく分かってる。","ENG":"But I know the activation system better than anyone.","TWN":"但我更了解讓線路轉換器運行的系統。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"지금 내가 가동 시스템을 완성하지 못하면 얼마나 많은 사람들이 더 죽을지 모른다고.","JPN":"私が今稼働システムを完成させなかったら、もっとたくさんの人が死ぬかもしれないんだよ。","ENG":"If I don't finish that system now, who knows how many more will die.","TWN":"如果我現在不完成啟動系統，不知道還會死多少人。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그러니까… 파티마…….","JPN":"だ、だから……ファティマ……","ENG":"S-so... Fatima...","TWN":"所、所以……法蒂瑪……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"날 지켜줘.","JPN":"私を守って。","ENG":"Protect me.","TWN":"保護我。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"무슨 멍청한 소리를 하시려나 했는데.","JPN":"またバカな話をしだすのかと思ったら。","ENG":"I expected something foolish.","TWN":"我還以為你又要說什麼蠢話了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이젠 썩 멋있는 말도 할 줄 아시게 되었군요.","JPN":"なかなか格好いいことも言えるようになりましたね。","ENG":"But it seems you can say something admirable now.","TWN":"沒想到現在也會說這麼帥的話了呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"좋습니다.","JPN":"分かりました。","ENG":"Very well.","TWN":"很好。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"파티마, 이건……?","JPN":"ファティマ、これは……？","ENG":"Fatima, what is this...?","TWN":"法蒂瑪，這是……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"절대로 그 벽 밖으로 나오지 마시길 바랍니다.","JPN":"絶対にその壁から出てこないでください。","ENG":"Do not step beyond that wall under any circumstance.","TWN":"請絕對不要踏出這面牆。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"닿는 순간 얼어버릴 테니까.","JPN":"触れた瞬間、凍ってしまいますので。","ENG":"Touch it and you will freeze solid.","TWN":"碰到的瞬間您會被凍住的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"난 너희 침식체들이 몇 마리가 오든 두렵지 않다.","JPN":"私は、お前たち侵食体が何匹かかって来ようが怖くない。","ENG":"I do not fear how many of you come.","TWN":"不管來多少侵蝕體，我都不害怕。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"내가 있는 이상, 이 빙벽이 무너질 일은 절대로 없으니까.","JPN":"私がいる限り、この氷壁が崩れることはないだろうから。","ENG":"As long as I am here, this ice wall will not fall.","TWN":"只要我還在，這面冰壁就絕不會崩塌。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그러니 덤벼라.","JPN":"だから、来い。","ENG":"So come at me.","TWN":"來吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"너희들의 그 짐승만도 못한 본능에 똑똑히 각인시켜 주겠다.","JPN":"獣以下のその本能に刻みつけてやる。","ENG":"I will make sure it is seared into your sub-beast instincts.","TWN":"我會在你們那禽獸不如的本能留下深刻的印象。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"파티마 자밀의 얼어붙은 분노는 그 어떤 것으로도 녹일 수 없다는 것을!","JPN":"ファティマ・ジャミルの凍てついた怒りは、何をもってしても溶かせないということを！","ENG":"That Fatima Jamil's frozen wrath cannot be melted by anything!","TWN":"任何東西都無法融化法蒂瑪賈米爾的冰封之怒！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};